+public:
+  ZClonerOopClosure(zaddress src, zaddress dst, size_t size)
+    : _src(src),
+      _dst(dst),
+      _size(size),
+      _is_dst_old(ZHeap::heap()->page(dst)->is_old()),
+      _copied_bytes(0) {}
