+  ~ZClonerOopClosure() {
+    precond(!to_oop(_src)->is_typeArray() || _copied_bytes == 0);
+
+    // Copy any potential tail
+    copy_to(_size);
+
+    // Copy will have copied the header, clear it.
+    to_oop(_dst)->init_mark();
+
+    postcond(_copied_bytes == _size);
+  }
